set-payload.value:
#[{
          originalPayload: vars.originalPayload default payload,
          errorDetails: {
            errorCode: vars.errorResponse.errorCode,
            errorMessage: vars.errorResponse.errorMessage,
            errorType: vars.errorResponse.errorType,
            failedAt: vars.errorResponse.failedAt,
            retryCount: vars.errorResponse.retryCount,
            lastRetryAt: vars.errorResponse.lastRetryAt
          },
          metadata: {
            correlationId: vars.errorResponse.correlationId,
            sourceQueue: vars.errorResponse.sourceQueue,
            originalTimestamp: now(),
            api: p("api.name"),
            environment: p("mule.env")
          }
        }]

#[{
      originalPayload: vars.originalPayload default payload,
      errorDetails: {
        errorCode: vars.errorResponse.errorCode,
        errorMessage: vars.errorResponse.errorMessage,
        errorType: vars.errorResponse.errorType,
        failedAt: vars.errorResponse.failedAt,
        retryCount: vars.errorResponse.retryCount,
        lastRetryAt: vars.errorResponse.lastRetryAt
      },
      metadata: {
        correlationId: vars.errorResponse.correlationId,
        sourceQueue: vars.errorResponse.sourceQueue,
        originalTimestamp: now(),
        api: p("api.name"),
        environment: p("env") default "dev"
      }
    }]
